                    // or just wait. Let's have gate sealers move to their positions.
                    int hi = gate_sealer[g];
                    if (!(humans[hi].r == human_build_row && humans[hi].c == gate_cols[g])) {
                        Pt target = {human_build_row, gate_cols[g]};
