            for (int i = 0; i < M; i++) {
                if (actions[i] != '.') continue; // already assigned (e.g., gate sealer)

                // Find next unbuilt cell in this human's assignment
                int target_col = -1;
                int best_dist = 999;
                for (int c : human_wall_cols[i]) {
                    if (wall[wall_row][c]) continue;
                    int dist = std::abs(humans[i].c - c) + std::abs(humans[i].r - human_build_row);
                    if (dist < best_dist) {
                        best_dist = dist;
                        target_col = c;
                    }
                }

                if (target_col == -1) {
                    // All my walls built - help with gates or stay
                    continue;
                }

                // Am I in position to build this cell?
                if (humans[i].r == human_build_row && humans[i].c == target_col) {
                    // Try to build
                    if (can_build(wall_row, target_col, i)) {
                        actions[i] = BUILD_CH[build_dir];
                    } else {
                        // Can't build here now (pet nearby), try another cell
                        bool found = false;
                        for (int c : human_wall_cols[i]) {
                            if (wall[wall_row][c]) continue;
                            if (c == target_col) continue;
                            if (humans[i].c == c && humans[i].r == human_build_row && can_build(wall_row, c, i)) {
                                // Already at position for this cell too? No, only if same col
                                break;
                            }
                        }
                        if (!found) {
