                    Pt target = {human_build_row, target_col};
                    std::vector<Pt> avoid;
                    actions[i] = move_toward(humans[i], target, avoid);
                }
            }
        } else { // MOVING_TO_ZONE
            for (int i = 0; i < M; i++) {
                if (humans[i].r >= zone_r_min && humans[i].r <= zone_r_max) continue;
                // Move toward zone
                Pt target;
                if (best_use_top) {
                    target = {zone_r_max, humans[i].c}; // move to bottom of zone (closest entry)
                    // Actually, just move toward the build row
                    target = {human_build_row, humans[i].c};
                } else {
                    target = {zone_r_min, humans[i].c};
                    target = {human_build_row, humans[i].c};
                }
