            for (int i = 0; i < M; i++) {
                if (actions[i] != '.') continue;
                if (humans[i].r < zone_r_min || humans[i].r > zone_r_max) continue;
                // This human is in zone - start building if possible
                int target_col = -1;
                int best_dist = 999;
