                        target_col = c;
                    }
                }
                if (target_col != -1) {
                    if (humans[i].r == human_build_row && humans[i].c == target_col) {
                        if (can_build(wall_row, target_col, i)) {
                            actions[i] = BUILD_CH[build_dir];
                        }
                    } else {
                        Pt target = {human_build_row, target_col};
                        std::vector<Pt> avoid;
                        actions[i] = move_toward(humans[i], target, avoid);
                    }
                }
            }
        }

        // Validate actions
        for (int i = 0; i < M; i++) {
            char a = actions[i];
            if (a == '.' ) continue;
            if (a == 'U' || a == 'D' || a == 'L' || a == 'R') {
                int d = -1;
                for (int k = 0; k < 4; k++) if (MOVE_CH[k] == a) d = k;
                int nr = humans[i].r + DR[d], nc = humans[i].c + DC[d];
                if (!valid(nr, nc) || wall[nr][nc]) actions[i] = '.';
            } else if (a == 'u' || a == 'd' || a == 'l' || a == 'r') {
                int d = -1;
                for (int k = 0; k < 4; k++) if (BUILD_CH[k] == a) d = k;
                int nr = humans[i].r + DR[d], nc = humans[i].c + DC[d];
