                // Check building constraints
                bool ok = true;
                for (auto& p : pets) {
                    if (p.r == nr && p.c == nc) { ok = false; break; }
                    if (std::abs(p.r - nr) + std::abs(p.c - nc) == 1) { ok = false; break; }
                }
                if (ok) {
                    for (int j = 0; j < M; j++) {
                        if (j == i) continue;
                        if (humans[j].r == nr && humans[j].c == nc) { ok = false; break; }
                    }
                }
                if (!ok) actions[i] = '.';
            }
        }

        // Output
        std::cout << actions << std::endl;

        // Apply our actions to local state
        for (int i = 0; i < M; i++) {
            char a = actions[i];
            if (a == 'u' || a == 'd' || a == 'l' || a == 'r') {
                int d = -1;
                for (int k = 0; k < 4; k++) if (BUILD_CH[k] == a) d = k;
                int nr = humans[i].r + DR[d], nc = humans[i].c + DC[d];
                if (valid(nr, nc) && !wall[nr][nc]) {
                    wall[nr][nc] = true;
                    if (nr == wall_row) wall_built[nc] = true;
                }
            } else if (a == 'U' || a == 'D' || a == 'L' || a == 'R') {
                int d = -1;
                for (int k = 0; k < 4; k++) if (MOVE_CH[k] == a) d = k;
                int nr = humans[i].r + DR[d], nc = humans[i].c + DC[d];
                if (valid(nr, nc) && !wall[nr][nc]) {
                    humans[i].r = nr;
                    humans[i].c = nc;
                }
            }
        }

        // Read pet movements
        for (int i = 0; i < N; i++) {
            std::string s;
            std::cin >> s;
            if (s == ".") continue;
            for (char ch : s) {
                for (int d = 0; d < 4; d++) {
                    if (ch == MOVE_CH[d]) {
                        pets[i].r += DR[d];
                        pets[i].c += DC[d];
                        break;
                    }
                }
            }
        }
    }

