                for (int k = 0; k < 4; k++) if (MOVE_CH[k] == a) d = k;
                int nr = humans[i].r + DR[d], nc = humans[i].c + DC[d];
                if (valid(nr, nc) && !wall[nr][nc]) {
                    humans[i].r = nr;
                    humans[i].c = nc;
                }
            }
        }

        // Read pet movements
        for (int i = 0; i < N; i++) {
            std::string s;
            std::cin >> s;
            if (s == ".") continue;
            for (char ch : s) {
                for (int d = 0; d < 4; d++) {
                    if (ch == MOVE_CH[d]) {
                        pets[i].r += DR[d];
                        pets[i].c += DC[d];
                        break;
                    }
                }
            }
        }
    }

    return 0;
}
