                    if (j == i) continue;
                    if (humans[j].r == nr && humans[j].c == nc) { human_there = true; break; }
                }
                if (human_there) actions[i] = '.';
            }
        }

        // Check for move conflicts: don't move into a cell being built this turn
        std::vector<Pt> built_this_turn;
        for (int i = 0; i < M; i++) {
            char a = actions[i];
            if (a == 'u' || a == 'd' || a == 'l' || a == 'r') {
                int d = -1;
                for (int k = 0; k < 4; k++) if (BUILD_CH[k] == a) d = k;
                built_this_turn.push_back({humans[i].r + DR[d], humans[i].c + DC[d]});
            }
        }
        for (int i = 0; i < M; i++) {
            char a = actions[i];
            if (a == 'U' || a == 'D' || a == 'L' || a == 'R') {
                int d = -1;
                for (int k = 0; k < 4; k++) if (MOVE_CH[k] == a) d = k;
                Pt dest = {humans[i].r + DR[d], humans[i].c + DC[d]};
                for (auto& b : built_this_turn) {
                    if (dest == b) { actions[i] = '.'; break; }
                }
            }
        }

        std::cout << actions << std::endl;

        // Apply actions locally
        for (int i = 0; i < M; i++) {
            char a = actions[i];
            if (a == 'u' || a == 'd' || a == 'l' || a == 'r') {
                int d = -1;
                for (int k = 0; k < 4; k++) if (BUILD_CH[k] == a) d = k;
                int nr = humans[i].r + DR[d], nc = humans[i].c + DC[d];
                if (valid(nr, nc)) wall[nr][nc] = true;
