                }
            } else if (human_phase[i] == ENTERING_BAND) {
                // Move toward band
                int target_r;
                if (humans[i].r < band_r_min) target_r = band_r_min;
                else target_r = band_r_max;
                Pt target = {target_r, humans[i].c};
                actions[i] = move_toward(humans[i], target);
            } else if (human_phase[i] == BUILDING) {
                // Find nearest unbuilt wall cell from my list
                Pt best_wall = {-1, -1};
                int best_dist = 9999;

                for (auto& w : human_walls[i]) {
                    if (wall[w.r][w.c]) continue;
                    int dist = std::abs(humans[i].r - w.r) + std::abs(humans[i].c - w.c);
                    if (dist < best_dist) {
