                        if (dist < best_dist) {
                            best_dist = dist;
                            best_wall = w;
                        }
                    }
                }

                if (best_wall.r == -1) {
                    // All main walls done, switch to sealing
                    human_phase[i] = SEALING;
                } else {
                    // Need to be adjacent to wall cell to build it
                    // Find best stand position (inside band, adjacent to wall)
                    Pt stand = {-1, -1};
                    int stand_dist = 9999;
                    for (int d = 0; d < 4; d++) {
