                            if (!valid(sr, sc) || wall[sr][sc]) continue;
                            int dd = std::abs(humans[i].r - sr) + std::abs(humans[i].c - sc);
                            if (dd < stand_dist) {
                                stand_dist = dd;
                                stand = {sr, sc};
                            }
                        }
                    }

