                if (wall[nr][nc]) { actions[i] = '.'; continue; }
                if (pet_blocks_build(nr, nc)) { actions[i] = '.'; continue; }
                bool human_there = false;
                for (int j = 0; j < M; j++) {
                    if (j == i) continue;
                    if (humans[j].r == nr && humans[j].c == nc) { human_there = true; break; }
                }
                if (human_there) actions[i] = '.';
            }
        }

        // Check for move conflicts: don't move into a cell being built this turn
        std::vector<Pt> built_this_turn;
        for (int i = 0; i < M; i++) {
            char a = actions[i];
            if (a == 'u' || a == 'd' || a == 'l' || a == 'r') {
                int d = -1;
                for (int k = 0; k < 4; k++) if (BUILD_CH[k] == a) d = k;
                built_this_turn.push_back({humans[i].r + DR[d], humans[i].c + DC[d]});
            }
        }
        for (int i = 0; i < M; i++) {
            char a = actions[i];
            if (a == 'U' || a == 'D' || a == 'L' || a == 'R') {
                int d = -1;
                for (int k = 0; k < 4; k++) if (MOVE_CH[k] == a) d = k;
                Pt dest = {humans[i].r + DR[d], humans[i].c + DC[d]};
                for (auto& b : built_this_turn) {
                    if (dest == b) { actions[i] = '.'; break; }
                }
            }
        }

        std::cout << actions << std::endl;

        // Apply actions locally
        for (int i = 0; i < M; i++) {
            char a = actions[i];
            if (a == 'u' || a == 'd' || a == 'l' || a == 'r') {
                int d = -1;
                for (int k = 0; k < 4; k++) if (BUILD_CH[k] == a) d = k;
                int nr = humans[i].r + DR[d], nc = humans[i].c + DC[d];
                if (valid(nr, nc)) wall[nr][nc] = true;
            } else if (a == 'U' || a == 'D' || a == 'L' || a == 'R') {
                int d = -1;
                for (int k = 0; k < 4; k++) if (MOVE_CH[k] == a) d = k;
                int nr = humans[i].r + DR[d], nc = humans[i].c + DC[d];
                if (valid(nr, nc) && !wall[nr][nc]) {
                    humans[i].r = nr;
                    humans[i].c = nc;
                }
            }
        }

        // Read pet movements
        for (int i = 0; i < N; i++) {
            std::string s;
            std::cin >> s;
            if (s == ".") continue;
            for (char ch : s) {
                for (int d = 0; d < 4; d++) {
                    if (ch == MOVE_CH[d]) {
                        pets[i].r += DR[d];
                        pets[i].c += DC[d];
                        break;
                    }
                }
            }
        }
    }

    return 0;
}
