#include <limits>
#include <cstring>

constexpr int GRID = 30;
constexpr int TURNS = 300;

const int DR[4] = {-1, 1, 0, 0};
const int DC[4] = {0, 0, -1, 1};
const char BUILD_CH[4] = {'u', 'd', 'l', 'r'};
const char MOVE_CH[4] = {'U', 'D', 'L', 'R'};

struct Pt { int r, c; };
bool operator==(Pt a, Pt b) { return a.r == b.r && a.c == b.c; }

bool wall[31][31];
int N, M;
std::vector<Pt> pets;
std::vector<int> pet_types;
std::vector<Pt> humans;

bool valid(int r, int c) { return r >= 1 && r <= GRID && c >= 1 && c <= GRID; }

bool pet_blocks_build(int r, int c) {
    for (auto& p : pets) {
        if (p.r == r && p.c == c) return true;
        if (std::abs(p.r - r) + std::abs(p.c - c) == 1) return true;
    }
    return false;
}

int bfs_dist[31][31];
Pt bfs_parent[31][31];

char move_toward(Pt from, Pt to) {
    if (from.r == to.r && from.c == to.c) return '.';

    memset(bfs_dist, -1, sizeof(bfs_dist));
    std::queue<Pt> q;
    bfs_dist[from.r][from.c] = 0;
    q.push(from);

    while (!q.empty()) {
        Pt cur = q.front(); q.pop();
        for (int d = 0; d < 4; d++) {
            int nr = cur.r + DR[d], nc = cur.c + DC[d];
            if (!valid(nr, nc) || wall[nr][nc] || bfs_dist[nr][nc] != -1) continue;
            bfs_dist[nr][nc] = bfs_dist[cur.r][cur.c] + 1;
            bfs_parent[nr][nc] = cur;
            if (nr == to.r && nc == to.c) {
                Pt step = to;
                while (!(bfs_parent[step.r][step.c] == from)) {
                    step = bfs_parent[step.r][step.c];
                }
                for (int k = 0; k < 4; k++) {
                    if (from.r + DR[k] == step.r && from.c + DC[k] == step.c) {
                        return MOVE_CH[k];
                    }
                }
                return '.';
            }
            q.push({nr, nc});
        }
    }
    return '.';
}

// Flood fill to count reachable area from a point
int flood_area(int start_r, int start_c) {
    memset(bfs_dist, -1, sizeof(bfs_dist));
    std::queue<Pt> q;
    bfs_dist[start_r][start_c] = 0;
    q.push({start_r, start_c});
    int area = 1;
    while (!q.empty()) {
        Pt cur = q.front(); q.pop();
        for (int d = 0; d < 4; d++) {
            int nr = cur.r + DR[d], nc = cur.c + DC[d];
            if (!valid(nr, nc) || wall[nr][nc] || bfs_dist[nr][nc] != -1) continue;
            bfs_dist[nr][nc] = 0;
            q.push({nr, nc});
            area++;
        }
    }
    return area;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::cin >> N;
    pets.resize(N);
    pet_types.resize(N);
    for (int i = 0; i < N; i++) {
        std::cin >> pets[i].r >> pets[i].c >> pet_types[i];
    }
