    humans.resize(M);
    for (int i = 0; i < M; i++) {
        std::cin >> humans[i].r >> humans[i].c;
    }
    memset(wall, false, sizeof(wall));

    // Strategy: Build TWO horizontal walls collaboratively.
    // Choose wall positions to minimize pets in the middle band while maximizing band area.
    // All humans work together, positioning in the middle band.

    // Evaluate all pairs of wall rows
    int best_r1 = -1, best_r2 = -1;
    double best_eval = -1e18;

    for (int r1 = 3; r1 <= GRID - 4; r1++) {
        for (int r2 = r1 + 3; r2 <= GRID - 2; r2++) {
            // Band between walls: rows r1+1 to r2-1
            int band_min = r1 + 1;
            int band_max = r2 - 1;
            int band_h = band_max - band_min + 1;
            if (band_h < 3) continue;

            int pets_in_band = 0;
            for (auto& p : pets) {
                if (p.r >= band_min && p.r <= band_max) pets_in_band++;
            }

            int humans_in_band = 0;
            int total_human_dist = 0;
            for (auto& h : humans) {
                if (h.r >= band_min && h.r <= band_max) {
                    humans_in_band++;
                } else {
                    int d = std::min(std::abs(h.r - band_min), std::abs(h.r - band_max));
                    total_human_dist += d;
                }
            }

            // Total walls to build = 60 cells
            // Time = 60 / M + max_travel_time
            double build_time = 60.0 / M + total_human_dist * 1.5 / M;
            // After building, we have area = band_h * 30 with pets_in_band pets
            double area = band_h * 30.0;
            double score = (area / 900.0) * std::pow(2.0, -pets_in_band);

            // Also consider top/bottom regions
            // Top: rows 1..r1-1
            int top_h = r1 - 1;
            if (top_h >= 2) {
                int pets_top = 0;
                for (auto& p : pets) if (p.r <= r1 - 1) pets_top++;
                double top_score = (top_h * 30.0 / 900.0) * std::pow(2.0, -pets_top);
                // But humans need to be there...
            }

            // Prefer fewer pets, more area, less travel, more humans inside
            double eval = score;
            eval -= build_time * 0.001;
            eval += humans_in_band * 0.05;

            if (eval > best_eval) {
                best_eval = eval;
                best_r1 = r1;
                best_r2 = r2;
            }
        }
    }

