        int pets_top = 0, pets_bot = 0;
        for (auto& p : pets) {
            if (p.r < r) pets_top++;
            else if (p.r > r) pets_bot++;
            // pet at wall row doesn't count for either side
        }

        int humans_top = 0, humans_bot = 0;
        int dist_top = 0, dist_bot = 0;
        for (auto& h : humans) {
            if (h.r < r) { humans_top++; }
            else if (h.r > r) { humans_bot++; }
            // human at wall row: needs to move to one side
        }

        double top_area = (r - 1) * 30.0;
        double bot_area = (GRID - r) * 30.0;
        double top_score = (top_area / 900.0) * std::pow(2.0, -pets_top);
        double bot_score = (bot_area / 900.0) * std::pow(2.0, -pets_bot);

