        }
        stand_row_for_wall2 = -1;
        build_dir_for_wall2 = -1;
    } else {
        stand_row_for_wall1 = wall_row1 + 1; // stand below wall1 (inside band), build up
        build_dir_for_wall1 = 0; // 'u'
        stand_row_for_wall2 = wall_row2 - 1; // stand above wall2 (inside band), build down
        build_dir_for_wall2 = 1; // 'd'
    }

    for (int turn = 0; turn < TURNS; turn++) {
        std::string actions(M, '.');

        // Count remaining unbuilt wall cells
        int unbuilt = 0;
        for (auto& w : wall_cells) {
            if (!wall[w.r][w.c]) unbuilt++;
        }

        bool wall_complete = (unbuilt == 0);

        for (int i = 0; i < M; i++) {
