                if (humans[i].r < target_zone_min || humans[i].r > target_zone_max) {
                    int target_r;
                    if (humans[i].r < target_zone_min) target_r = target_zone_min;
                    else target_r = target_zone_max;
                    Pt target = {target_r, humans[i].c};
                    actions[i] = move_toward(humans[i], target);
                }
