    int top_width = GRID / top_count;
    int bot_width = bot_count > 0 ? GRID / bot_count : 0;

    for (int i = 0; i < M; i++) {
        Enclosure& e = enc[i];
        bool is_top = (i < top_count);
        int idx = is_top ? i : (i - top_count);
        int count = is_top ? top_count : bot_count;
        int w = GRID / count;

        int c_start = 1 + idx * w;
        int c_end = (idx == count - 1) ? GRID : (c_start + w - 1);

        if (is_top) {
            // Interior: rows 1 to target_h, cols c_start to c_end
            e.ir_min = 1;
            e.ir_max = target_h;
            e.ic_min = c_start;
            e.ic_max = c_end;
            // Walls needed:
            // Bottom wall: row (target_h + 1), cols c_start to c_end
            // Left wall (if c_start > 1): col (c_start - 1), rows 1 to target_h+1
            // Right wall (if c_end < 30): col (c_end + 1), rows 1 to target_h+1
            // Top wall: row 0 is boundary (off-grid), no build needed

            // Bottom wall
            for (int c = c_start; c <= c_end; c++) {
                e.walls.push_back({target_h + 1, c});
            }
            // Left wall (if not at grid edge)
            if (c_start > 1) {
                for (int r = 1; r <= target_h + 1; r++) {
                    e.walls.push_back({r, c_start - 1});
                }
            }
            // Right wall (if not at grid edge)
            if (c_end < GRID) {
                for (int r = 1; r <= target_h + 1; r++) {
                    e.walls.push_back({r, c_end + 1});
                }
            }

            // Gate: middle of bottom wall
            int gate_c = (c_start + c_end) / 2;
            e.gate = {target_h + 1, gate_c};
            e.gate_stand = {target_h, gate_c}; // stand above gate
            e.gate_build_dir = 1; // 'd' to build below

        } else {
            // Bottom side
            e.ir_min = GRID - target_h + 1;
            e.ir_max = GRID;
            e.ic_min = c_start;
            e.ic_max = c_end;

            // Top wall: row (GRID - target_h), cols c_start to c_end
            for (int c = c_start; c <= c_end; c++) {
