                    e.walls.push_back({r, c_start - 1});
                }
            }
            // Right wall
            if (c_end < GRID) {
                for (int r = GRID - target_h; r <= GRID; r++) {
                    e.walls.push_back({r, c_end + 1});
                }
            }

            int gate_c = (c_start + c_end) / 2;
            e.gate = {GRID - target_h, gate_c};
            e.gate_stand = {GRID - target_h + 1, gate_c}; // stand below gate
            e.gate_build_dir = 0; // 'u' to build above
        }

