                        if (humans[j].r == e.gate.r && humans[j].c == e.gate.c) { ht = true; break; }
                    }
                    if (!ht) {
                        actions[i] = BUILD_CH[e.gate_build_dir];
                        built_this_turn.push_back(e.gate);
                    }
                }
