bool operator==(Pt a, Pt b) { return a.r == b.r && a.c == b.c; }

bool wall[31][31];
int N, M;
std::vector<Pt> pets;
std::vector<int> pet_types;
std::vector<Pt> humans;

bool valid(int r, int c) { return r >= 1 && r <= GRID && c >= 1 && c <= GRID; }

bool pet_blocks_build(int r, int c) {
    for (auto& p : pets) {
        if (p.r == r && p.c == c) return true;
        if (std::abs(p.r - r) + std::abs(p.c - c) == 1) return true;
    }
    return false;
}

int bfs_d[31][31];
Pt bfs_p[31][31];

char move_toward(Pt from, Pt to) {
    if (from.r == to.r && from.c == to.c) return '.';
    memset(bfs_d, -1, sizeof(bfs_d));
    std::queue<Pt> q;
    bfs_d[from.r][from.c] = 0;
    q.push(from);
    while (!q.empty()) {
        Pt cur = q.front(); q.pop();
        for (int d = 0; d < 4; d++) {
            int nr = cur.r + DR[d], nc = cur.c + DC[d];
            if (!valid(nr, nc) || wall[nr][nc] || bfs_d[nr][nc] != -1) continue;
            bfs_d[nr][nc] = bfs_d[cur.r][cur.c] + 1;
            bfs_p[nr][nc] = cur;
            if (nr == to.r && nc == to.c) {
                Pt step = to;
                while (!(bfs_p[step.r][step.c] == from)) {
                    step = bfs_p[step.r][step.c];
                }
                for (int k = 0; k < 4; k++) {
                    if (from.r + DR[k] == step.r && from.c + DC[k] == step.c)
                        return MOVE_CH[k];
                }
                return '.';
            }
            q.push({nr, nc});
        }
    }
    return '.';
}

struct Enclosure {
    // Interior bounds (passable cells inside enclosure)
    int ir_min, ir_max, ic_min, ic_max;
    // Wall cells to build (only those on-grid; off-grid boundary handled by grid edge)
    std::vector<Pt> walls;
    // Gate cell: last wall cell to seal
    Pt gate;
    // Stand position: where to stand to seal gate
    Pt gate_stand;
    int gate_build_dir;
    Pt center;
    int interior_area;
};

bool is_interior(const Enclosure& e, int r, int c) {
    return r >= e.ir_min && r <= e.ir_max && c >= e.ic_min && c <= e.ic_max;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::cin >> N;
    pets.resize(N);
    pet_types.resize(N);
    for (int i = 0; i < N; i++) {
        std::cin >> pets[i].r >> pets[i].c >> pet_types[i];
    }
    std::cin >> M;
    humans.resize(M);
    for (int i = 0; i < M; i++) {
        std::cin >> humans[i].r >> humans[i].c;
    }
    memset(wall, false, sizeof(wall));

    // Strategy: Each human builds a rectangular enclosure touching grid edges.
    // Use top edge for some humans, bottom edge for others.
    // Gate in the interior wall (not touching edge) - last cell sealed.
    // Human gets inside, waits for no pets, then seals gate.

    // Layout: divide horizontally
    // Top humans: enclosures touching row=1 boundary
    // Bottom humans: enclosures touching row=30 boundary
    int top_count = (M + 1) / 2;
    int bot_count = M - top_count;

    std::vector<Enclosure> enc(M);

    // Target enclosure height (from edge inward)
    int target_h = 7; // interior height = target_h rows
    // Width: divide available width among humans on each side
    int top_width = GRID / top_count;
    int bot_width = bot_count > 0 ? GRID / bot_count : 0;

    for (int i = 0; i < M; i++) {
        Enclosure& e = enc[i];
        bool is_top = (i < top_count);
        int idx = is_top ? i : (i - top_count);
        int count = is_top ? top_count : bot_count;
        int w = GRID / count;

        int c_start = 1 + idx * w;
        int c_end = (idx == count - 1) ? GRID : (c_start + w - 1);

        if (is_top) {
            // Interior: rows 1 to target_h, cols c_start to c_end
            e.ir_min = 1;
            e.ir_max = target_h;
            e.ic_min = c_start;
            e.ic_max = c_end;
            // Walls needed:
            // Bottom wall: row (target_h + 1), cols c_start to c_end
            // Left wall (if c_start > 1): col (c_start - 1), rows 1 to target_h+1
            // Right wall (if c_end < 30): col (c_end + 1), rows 1 to target_h+1
            // Top wall: row 0 is boundary (off-grid), no build needed

            // Bottom wall
            for (int c = c_start; c <= c_end; c++) {
                e.walls.push_back({target_h + 1, c});
            }
            // Left wall (if not at grid edge)
            if (c_start > 1) {
                for (int r = 1; r <= target_h + 1; r++) {
                    e.walls.push_back({r, c_start - 1});
                }
            }
            // Right wall (if not at grid edge)
            if (c_end < GRID) {
                for (int r = 1; r <= target_h + 1; r++) {
                    e.walls.push_back({r, c_end + 1});
                }
            }

            // Gate: middle of bottom wall
            int gate_c = (c_start + c_end) / 2;
            e.gate = {target_h + 1, gate_c};
            e.gate_stand = {target_h, gate_c}; // stand above gate
            e.gate_build_dir = 1; // 'd' to build below

        } else {
            // Bottom side
            e.ir_min = GRID - target_h + 1;
            e.ir_max = GRID;
            e.ic_min = c_start;
            e.ic_max = c_end;

            // Top wall: row (GRID - target_h), cols c_start to c_end
            for (int c = c_start; c <= c_end; c++) {
                e.walls.push_back({GRID - target_h, c});
            }
            // Left wall
            if (c_start > 1) {
                for (int r = GRID - target_h; r <= GRID; r++) {
                    e.walls.push_back({r, c_start - 1});
                }
            }
            // Right wall
            if (c_end < GRID) {
                for (int r = GRID - target_h; r <= GRID; r++) {
                    e.walls.push_back({r, c_end + 1});
                }
            }

            int gate_c = (c_start + c_end) / 2;
            e.gate = {GRID - target_h, gate_c};
            e.gate_stand = {GRID - target_h + 1, gate_c}; // stand below gate
            e.gate_build_dir = 0; // 'u' to build above
        }

        // Remove duplicate wall cells
        std::sort(e.walls.begin(), e.walls.end(), [](Pt a, Pt b) {
            return a.r < b.r || (a.r == b.r && a.c < b.c);
        });
        e.walls.erase(std::unique(e.walls.begin(), e.walls.end(), [](Pt a, Pt b) {
            return a == b;
        }), e.walls.end());

        e.center = {(e.ir_min + e.ir_max) / 2, (e.ic_min + e.ic_max) / 2};
        e.interior_area = (e.ir_max - e.ir_min + 1) * (e.ic_max - e.ic_min + 1);
    }

    // State per human
    // Phase 0: Build all walls except gate
    // Phase 1: Get inside enclosure (through gate)
    // Phase 2: Wait at gate_stand for no pets inside, then seal
    // Phase 3: Done

    std::vector<int> phase(M, 0);

    for (int turn = 0; turn < TURNS; turn++) {
        std::string actions(M, '.');
        std::vector<Pt> built_this_turn;

        for (int i = 0; i < M; i++) {
            Enclosure& e = enc[i];

            // Count unbuilt walls (excluding gate if phase < 2)
            int unbuilt_non_gate = 0;
            for (auto& w : e.walls) {
                if (w == e.gate) continue;
                if (!wall[w.r][w.c]) unbuilt_non_gate++;
            }
            bool gate_built = wall[e.gate.r][e.gate.c];

            // Update phase
            if (gate_built) {
                phase[i] = 3;
            } else if (unbuilt_non_gate == 0) {
                // All walls except gate built
                // Check if human is inside
                bool inside = is_interior(e, humans[i].r, humans[i].c);
                if (inside) {
                    phase[i] = 2; // ready to seal
                } else {
                    phase[i] = 1; // need to get inside
                }
            } else {
                phase[i] = 0;
            }

            if (phase[i] == 3) {
                // Done - if outside, try to move inside
                if (!is_interior(e, humans[i].r, humans[i].c)) {
                    actions[i] = move_toward(humans[i], e.center);
                }
                continue;
            }

            if (phase[i] == 2) {
                // At gate stand position, waiting to seal
                if (!(humans[i] == e.gate_stand)) {
                    actions[i] = move_toward(humans[i], e.gate_stand);
                    continue;
                }

                // Check: no pets inside enclosure
                bool pets_inside = false;
                for (auto& p : pets) {
                    if (is_interior(e, p.r, p.c)) {
                        pets_inside = true;
                        break;
                    }
                }

                if (!pets_inside && !pet_blocks_build(e.gate.r, e.gate.c)) {
                    // Check no human at gate position
                    bool ht = false;
                    for (int j = 0; j < M; j++) {
                        if (j == i) continue;
                        if (humans[j].r == e.gate.r && humans[j].c == e.gate.c) { ht = true; break; }
                    }
                    if (!ht) {
                        actions[i] = BUILD_CH[e.gate_build_dir];
                        built_this_turn.push_back(e.gate);
                    }
                }
                // else wait
                continue;
            }

            if (phase[i] == 1) {
                // Need to get inside through gate
                // Move toward gate_stand (which is inside)
                actions[i] = move_toward(humans[i], e.gate_stand);
                continue;
            }

            // Phase 0: Building walls (except gate)
            // Find nearest unbuilt non-gate wall
            Pt best_w = {-1, -1};
            int best_cost = 9999;
            Pt best_stand = {-1, -1};
            int best_build_d = -1;

            for (auto& w : e.walls) {
                if (w == e.gate) continue;
                if (wall[w.r][w.c]) continue;

                for (int d = 0; d < 4; d++) {
                    int sr = w.r + DR[d], sc = w.c + DC[d];
                    if (!valid(sr, sc) || wall[sr][sc]) continue;
                    int dist = std::abs(humans[i].r - sr) + std::abs(humans[i].c - sc);
                    if (dist < best_cost) {
                        best_cost = dist;
                        best_w = w;
                        best_stand = {sr, sc};
                        best_build_d = (d ^ 1); // reverse direction: if stand is above wall, build down
                        // Actually need exact direction from stand to wall
                    }
                }
            }

            if (best_w.r == -1) continue;

            // Compute correct build direction from best_stand to best_w
            best_build_d = -1;
            for (int d = 0; d < 4; d++) {
                if (best_stand.r + DR[d] == best_w.r && best_stand.c + DC[d] == best_w.c) {
                    best_build_d = d;
                    break;
                }
            }

            if (humans[i] == best_stand) {
                // Try to build
                if (!pet_blocks_build(best_w.r, best_w.c) && best_build_d >= 0) {
                    bool ht = false;
                    for (int j = 0; j < M; j++) {
                        if (j == i) continue;
                        if (humans[j].r == best_w.r && humans[j].c == best_w.c) { ht = true; break; }
                    }
                    if (!ht) {
                        actions[i] = BUILD_CH[best_build_d];
                        built_this_turn.push_back(best_w);
                    }
                }
                // If can't build, try other adjacent walls
                if (actions[i] == '.') {
                    for (auto& w : e.walls) {
                        if (w == e.gate || wall[w.r][w.c]) continue;
                        for (int d = 0; d < 4; d++) {
                            if (humans[i].r + DR[d] == w.r && humans[i].c + DC[d] == w.c) {
                                if (!pet_blocks_build(w.r, w.c)) {
                                    bool ht2 = false;
                                    for (int j = 0; j < M; j++) {
                                        if (j == i) continue;
                                        if (humans[j].r == w.r && humans[j].c == w.c) { ht2 = true; break; }
                                    }
                                    if (!ht2) {
                                        actions[i] = BUILD_CH[d];
                                        built_this_turn.push_back(w);
                                        goto done_human;
                                    }
                                }
                            }
                        }
                    }
                }
            } else {
                actions[i] = move_toward(humans[i], best_stand);
            }
            done_human:;
        }

        // Validate
        for (int i = 0; i < M; i++) {
            char a = actions[i];
            if (a == '.') continue;
            if (a == 'U' || a == 'D' || a == 'L' || a == 'R') {
                int d = -1;
                for (int k = 0; k < 4; k++) if (MOVE_CH[k] == a) d = k;
                int nr = humans[i].r + DR[d], nc = humans[i].c + DC[d];
                if (!valid(nr, nc) || wall[nr][nc]) { actions[i] = '.'; continue; }
                for (auto& b : built_this_turn) {
                    if (b.r == nr && b.c == nc) { actions[i] = '.'; break; }
                }
            } else {
                int d = -1;
                for (int k = 0; k < 4; k++) if (BUILD_CH[k] == a) d = k;
                int nr = humans[i].r + DR[d], nc = humans[i].c + DC[d];
                if (!valid(nr, nc)) { actions[i] = '.'; continue; }
                if (wall[nr][nc]) { actions[i] = '.'; continue; }
                if (pet_blocks_build(nr, nc)) { actions[i] = '.'; continue; }
                bool ht = false;
                for (int j = 0; j < M; j++) {
                    if (j == i) continue;
                    if (humans[j].r == nr && humans[j].c == nc) { ht = true; break; }
                }
                if (ht) actions[i] = '.';
            }
        }

        std::cout << actions << std::endl;

        // Apply
        for (int i = 0; i < M; i++) {
            char a = actions[i];
            if (a == 'u' || a == 'd' || a == 'l' || a == 'r') {
                int d = -1;
                for (int k = 0; k < 4; k++) if (BUILD_CH[k] == a) d = k;
                int nr = humans[i].r + DR[d], nc = humans[i].c + DC[d];
                if (valid(nr, nc)) wall[nr][nc] = true;
            } else if (a == 'U' || a == 'D' || a == 'L' || a == 'R') {
                int d = -1;
                for (int k = 0; k < 4; k++) if (MOVE_CH[k] == a) d = k;
                int nr = humans[i].r + DR[d], nc = humans[i].c + DC[d];
                if (valid(nr, nc) && !wall[nr][nc]) {
                    humans[i].r = nr;
                    humans[i].c = nc;
                }
            }
        }

        // Read pet movements
        for (int i = 0; i < N; i++) {
            std::string s;
            std::cin >> s;
            if (s == ".") continue;
            for (char ch : s) {
                for (int d = 0; d < 4; d++) {
                    if (ch == MOVE_CH[d]) {
                        pets[i].r += DR[d];
                        pets[i].c += DC[d];
                        break;
                    }
                }
            }
        }
    }

    return 0;
}
